// Checkpoint tracker for resumable processing
class CheckpointTracker {
    constructor(context) {
        this.context = context;
        this.processedCount = 0;
        this.failedCount = 0;
        this.skippedCount = 0;
        this.lastProcessedId = null;
        this.continuationToken = null;
        this.startTime = Date.now();
        this.errors = [];
    }

    recordSuccess(itemId) {
        this.processedCount++;
        this.lastProcessedId = itemId;
    }

    recordFailure(itemId, error) {
        this.failedCount++;
        this.errors.push({ itemId, error: error.message, timestamp: new Date().toISOString() });
    }

    recordSkip(itemId, reason) {
        this.skippedCount++;
        this.context.log(`Skipped item ${itemId}: ${reason}`);
    }

    isTimeRemaining() {
        const elapsed = Date.now() - this.startTime;
        return elapsed < PROCESSING_TIMEOUT_MS;
    }

    getElapsedMs() {
        return Date.now() - this.startTime;
    }

    getSummary() {
        return {
            processedCount: this.processedCount,
            failedCount: this.failedCount,
            skippedCount: this.skippedCount,
            lastProcessedId: this.lastProcessedId,
            continuationToken: this.continuationToken,
            elapsedMs: this.getElapsedMs(),
            errors: this.errors.slice(0, 50) // Limit error log size
        };
    }
}

// Retry helper with exponential backoff
async function retryWithBackoff(fn, context, maxRetries = MAX_RETRY_ATTEMPTS) {
    let lastError;
    for (let attempt = 0; attempt <= maxRetries; attempt++) {
        try {
            return await fn();
        } catch (error) {
            lastError = error;
            if (attempt < maxRetries) {
                // Handle throttling (429) with longer backoff
                const isThrottled = error.code === 429 || error.statusCode === 429;
                const retryAfterMs = isThrottled
                    ? (error.retryAfterInMs || error.retryAfterInMilliseconds || 1000)
                    : Math.pow(2, attempt) * 500;

                context.log.warn(
                    `Attempt ${attempt + 1} failed${isThrottled ? ' (throttled)' : ''}, ` +
                    `retrying in ${retryAfterMs}ms: ${error.message}`
                );
                await sleep(retryAfterMs);
            }
        }
    }
    throw lastError;
}

function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

