// Batch write processed items to Cosmos DB output container
async function writeBatchToCosmosDB(items, outputContainer, context) {
    const results = { succeeded: 0, failed: 0 };

    // Use bulk operations for better throughput
    const operations = items.map(item => ({
        operationType: 'Upsert',
        resourceBody: item,
        partitionKey: item.partitionKey
    }));

    // Process in sub-batches to avoid overwhelming Cosmos DB
    const SUB_BATCH_SIZE = 100;
    for (let i = 0; i < operations.length; i += SUB_BATCH_SIZE) {
        const subBatch = operations.slice(i, i + SUB_BATCH_SIZE);

        try {
            const bulkResponse = await retryWithBackoff(
                () => outputContainer.items.bulk(subBatch),
                context
            );

            for (const result of bulkResponse) {
                if (result.statusCode >= 200 && result.statusCode < 300) {
                    results.succeeded++;
                } else {
                    results.failed++;
                    context.log.warn(`Bulk write item failed with status ${result.statusCode}`);
                }
            }
        } catch (error) {
            // Fallback to individual upserts if bulk fails
            context.log.warn(`Bulk write failed, falling back to individual upserts: ${error.message}`);
            for (const op of subBatch) {
                try {
                    await retryWithBackoff(
                        () => outputContainer.items.upsert(op.resourceBody),
                        context
                    );
                    results.succeeded++;
                } catch (itemError) {
                    results.failed++;
                    context.log.error(`Failed to upsert item: ${itemError.message}`);
                }
            }
        }
    }

    return results;
}

